INSERT INTO public.changelog (version, title, body, released_at) VALUES ('1.6.0', 'Ultimate Dungeon Scrawler — ادیتور نقشه', E'ویرایشگر Sketch به یک ابزار کامل نقشه‌کشی TTRPG ارتقا یافت:\n\n• بوم بی‌نهایت (Infinite Canvas) بدون Scroll Bar — Pan با MMB یا Shift+Drag، Zoom با Ctrl+Wheel\n• گرید مربعی و شش‌ضلعی (Hex) با snap-to-grid\n• ابزارهای اختصاصی TTRPG: Wall، Room، Cave Brush (خط ارگانیک)\n• Random Dungeon Generator با الگوریتم BSP + اتصال اتاق‌ها\n• حالت سه‌بعدی: Isometric / Perspective با Three.js، دیوارها extrude شده، نورپردازی و سایه\n• کنترل دوربین به سبک 3ds Max: LMB=Orbit، MMB=Pan، RMB=Dolly، RMB+WASD/QE=Fly، Shift=Fast، ESC=خروج\n• آیکن دوربین در گوشه بوم وقتی حالت 3D فعال است\n• Screenshot PNG از نمای سه‌بعدی\n• آیکن‌های FontAwesome 6 و Game-Icons (بیش از ۴۰۰۰ آیکن فانتزی) در دسترس در کل سایت', now())
ON CONFLICT DO NOTHING;